// AnimatedContainer smoothly interpolates any changed property.
class BreathBox extends StatefulWidget {
  const BreathBox({super.key});
  @override State<BreathBox> createState() => _BreathBoxState();
}
class _BreathBoxState extends State<BreathBox> {
  bool _big = false;

  @override
  Widget build(BuildContext context) => GestureDetector(
    onTap: () => setState(() => _big = !_big),
    child: AnimatedContainer(
      duration: const Duration(milliseconds: 400),
      curve: Curves.easeInOut,
      width: _big ? 200 : 100,
      height: _big ? 200 : 100,
      decoration: BoxDecoration(
        color: _big ? Colors.deepPurple : Colors.blueGrey,
        borderRadius: BorderRadius.circular(_big ? 100 : 12),
      ),
    ),
  );
}

