// A pulse animation controlled by an AnimationController + Tween.
class Pulse extends StatefulWidget {
  const Pulse({super.key});
  @override State<Pulse> createState() => _PulseState();
}
class _PulseState extends State<Pulse> with SingleTickerProviderStateMixin {
  late final AnimationController _ctrl = AnimationController(
    vsync: this,
    duration: const Duration(milliseconds: 900),
  )..repeat(reverse: true);

  late final Animation<double> _scale = Tween<double>(begin: 1.0, end: 1.4)
    .chain(CurveTween(curve: Curves.easeInOut))
    .animate(_ctrl);

  @override
  void dispose() {
    _ctrl.dispose();     // MUST dispose the controller
    super.dispose();
  }

  @override
  Widget build(BuildContext context) => AnimatedBuilder(
    animation: _scale,
    // The `child` is built ONCE and passed into `builder` — Flutter optimizes
    // by NOT rebuilding the child on every animation frame.
    child: const Icon(Icons.favorite, color: Colors.red, size: 48),
    builder: (context, child) => Transform.scale(scale: _scale.value, child: child),
  );
}

// Key points:
//   * SingleTickerProviderStateMixin gives us `vsync: this` — the ticker
//     source. Without vsync, the controller has no clock.
//   * The controller lives in State; disposed in dispose().
//   * AnimatedBuilder rebuilds every frame; passing a static `child:` avoids
//     rebuilding the expensive part.

