import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: Gallery()));

class Gallery extends StatelessWidget {
  const Gallery({super.key});
  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Animation gallery')),
    body: const Padding(
      padding: EdgeInsets.all(16),
      child: Column(
        mainAxisAlignment: MainAxisAlignment.spaceEvenly,
        children: [
          Text('Tap the boxes'),
          BreathBox(),                   // implicit — AnimatedContainer
          Pulse(),                       // explicit — AnimationController + Tween
          _FadeIn(child: Text('Faded in via TweenAnimationBuilder')),
        ],
      ),
    ),
  );
}

class _FadeIn extends StatelessWidget {
  const _FadeIn({required this.child});
  final Widget child;

  // TweenAnimationBuilder — a one-shot implicit animation driven by a Tween.
  // Great for entrance animations.
  @override
  Widget build(BuildContext context) => TweenAnimationBuilder<double>(
    tween: Tween(begin: 0, end: 1),
    duration: const Duration(milliseconds: 800),
    curve: Curves.easeOut,
    builder: (context, opacity, child) => Opacity(opacity: opacity, child: child),
    child: child,
  );
}

